import math

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def main():
    T = int(input())
    for _ in range(T):
        N = int(input())
        arr = list(map(int, input().split()))
        max_len = -1
        for i in range(N):
            for j in range(i + 1, N):
                subarray = arr[i:j + 1]
                result = subarray[0]
                for k in range(1, len(subarray)):
                    result = gcd(result, subarray[k])
                if result == 1:
                    max_len = max(max_len, j - i + 1)
        print(max_len)

if __name__ == '__main__':
    main()

